function toNumber(value, fallback = 0) {
  if (value === null || value === undefined || value === '') return fallback;
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function round2(value) {
  return Math.round((value + Number.EPSILON) * 100) / 100;
}

const body = $json.body ?? $json;
let students = [];

if (Array.isArray(body)) {
  students = body;
} else if (Array.isArray(body.students)) {
  students = body.students;
} else if (Array.isArray(body.data)) {
  students = body.data;
} else {
  throw new Error("Expected payload format: { \"students\": [ ... ] }");
}

const processed = students.map((row, index) => {
  const studentId = row.Student_ID ?? row.student_id ?? row.id ?? index + 1;
  const studentName = row.Student_Name ?? row.student_name ?? row.name ?? `Student ${index + 1}`;
  const className = row.Class ?? row.class ?? '';
  const section = row.Section ?? row.section ?? '';
  const physics = toNumber(row.Physics_Marks ?? row.physics ?? row.physics_marks);
  const chemistry = toNumber(row.Chemistry_Marks ?? row.chemistry ?? row.chemistry_marks);
  const math = toNumber(row.Math_Marks ?? row.math ?? row.math_marks);
  const attendance = toNumber(row.Attendance_Percentage ?? row.attendance ?? row.attendance_percentage);
  const homework = toNumber(row.Homework_Completion_Percentage ?? row.homework ?? row.homework_completion_percentage);
  const parentEmail = row.Parent_Email ?? row.parent_email ?? '';
  const teacherEmail = row.Teacher_Email ?? row.teacher_email ?? '';
  const phoneNumber = row.Phone_Number ?? row.phone_number ?? '';

  const averageMarks = round2((physics + chemistry + math) / 3);
  const marksRisk = round2(100 - averageMarks);
  const attendanceRisk = round2(100 - attendance);
  const homeworkRisk = round2(100 - homework);

  const riskScore = round2((0.5 * marksRisk) + (0.3 * attendanceRisk) + (0.2 * homeworkRisk));

  let riskCategory = "Low Risk";
  if (riskScore >= 40) {
    riskCategory = "High Risk";
  } else if (riskScore >= 25) {
    riskCategory = "Medium Risk";
  }

  const subjects = [
    { name: "Physics", score: physics },
    { name: "Chemistry", score: chemistry },
    { name: "Math", score: math }
  ].sort((a, b) => a.score - b.score);

  const weakSubject = subjects[0].name;
  const weakSubjectScore = round2(subjects[0].score);

  const suggestions = [];
  if (averageMarks < 60) suggestions.push("Improve overall subject performance with a focused weekly study plan.");
  if (attendance < 75) suggestions.push("Improve attendance to avoid concept gaps and missed classroom practice.");
  if (homework < 70) suggestions.push("Complete homework regularly to strengthen revision and retention.");
  if (weakSubjectScore < 50) suggestions.push(`Give extra practice in ${weakSubject} and schedule targeted doubt-solving.`);
  if (riskScore >= 40) suggestions.push("Teacher intervention recommended this week with parent follow-up.");
  if (suggestions.length === 0) suggestions.push("Student is stable. Continue current learning routine.");

  return {
    Student_ID: studentId,
    Student_Name: studentName,
    Class: className,
    Section: section,
    Physics_Marks: physics,
    Chemistry_Marks: chemistry,
    Math_Marks: math,
    Attendance_Percentage: attendance,
    Homework_Completion_Percentage: homework,
    Parent_Email: parentEmail,
    Teacher_Email: teacherEmail,
    Phone_Number: phoneNumber,
    Average_Marks: averageMarks,
    Marks_Risk: marksRisk,
    Attendance_Risk: attendanceRisk,
    Homework_Risk: homeworkRisk,
    Risk_Score: riskScore,
    Risk_Category: riskCategory,
    Weak_Subject: weakSubject,
    Suggestion: suggestions.join(" "),
  };
});

const teacherAlertList = processed
  .filter(s => s.Risk_Category === "High Risk")
  .sort((a, b) => b.Risk_Score - a.Risk_Score)
  .map(s => ({
    Student_ID: s.Student_ID,
    Student_Name: s.Student_Name,
    Class: s.Class,
    Section: s.Section,
    Risk_Score: s.Risk_Score,
    Weak_Subject: s.Weak_Subject,
    Teacher_Email: s.Teacher_Email,
    Parent_Email: s.Parent_Email,
    Suggestion: s.Suggestion,
  }));

const summary = {
  total_students: processed.length,
  high_risk_count: processed.filter(s => s.Risk_Category === "High Risk").length,
  medium_risk_count: processed.filter(s => s.Risk_Category === "Medium Risk").length,
  low_risk_count: processed.filter(s => s.Risk_Category === "Low Risk").length,
};

return [{
  json: {
    success: true,
    summary,
    teacher_alert_list: teacherAlertList,
    all_students_processed: processed
  }
}];

const teacherAlertList = $json.teacher_alert_list || [];
const lines = teacherAlertList.map((s, i) =>
  `${i + 1}. ${s.Student_Name} | Risk Score: ${s.Risk_Score} | Weak Subject: ${s.Weak_Subject} | Teacher: ${s.Teacher_Email || 'N/A'}`
);

return [{
  json: {
    ...$json,
    email_subject: `High Risk Student Alert (${teacherAlertList.length} students)`,
    email_body: [
      "Dummy alert generated by n8n.",
      "",
      "High risk students:",
      ...lines
    ].join("\n")
  }
}];
